noncompliant:
char *str = NULL;
size_t len = strlen(str); // Noncompliant: NULL pointer dereference

char buffer[5];
buffer[0] = 'H';
buffer[1] = 'i';
// Missing null terminator
size_t len = strlen(buffer); // Noncompliant: undefined behavior - not null terminated

compliant:
char *str = "Hello";
if (str != NULL) {
    size_t len = strlen(str); // Compliant: checked for NULL
}

// Or use safer alternatives:
size_t strnlen_safe(const char *s, size_t maxlen) {
    if (s == NULL) return 0;
    return strnlen(s, maxlen); // Compliant: bounded length check
}
